import SwiftUI
struct HomeView:View{let store:FamiliarStore;var body:some View{ZStack{store.style.accent.opacity(0.18).ignoresSafeArea();VStack(spacing:20){HStack{VStack(alignment:.leading){Text(store.petName).font(.largeTitle.bold());Text("\(store.mood) · Level \(store.level)")}.frame(maxWidth:.infinity,alignment:.leading);NavigationLink(destination:StylePickerView(store:store)){Image(systemName:"paintpalette").font(.title2)}};Spacer();Image("Ember").resizable().scaledToFit().frame(maxHeight:390).accessibilityLabel("Ember, a small dragon");Text(store.style.dialogue).font(.headline).italic();HStack{MetricView(title:"Bond",value:store.bond,icon:"heart");MetricView(title:"Energy",value:store.energy,icon:"bolt")};Button("Focus together",systemImage:"sparkles"){}.buttonStyle(.borderedProminent).controlSize(.large).tint(store.style.accent)}.padding()}.navigationBarHidden(true)}}
private struct MetricView:View{let title:String;let value:Double;let icon:String;var body:some View{VStack(alignment:.leading){Label(title,systemImage:icon);ProgressView(value:value)}.frame(maxWidth:.infinity)}}
